// Copies the canonical shared/permissions.ts into backend/src/_shared/ before
// the backend compiles. This exists because tsc's `rootDir` requires every
// source file it compiles to live inside that directory — shared/permissions.ts
// sits one level up, outside backend/src entirely, so importing it directly
// fails with TS6059 the moment `tsc` (not just type-checking, but actually
// emitting output) tries to build it.
//
// This keeps shared/permissions.ts as the one real, hand-edited file — the
// copy in backend/src/_shared/ is regenerated by this script on every build
// and dev run, never edited directly (see .gitignore).
const fs = require('fs');
const path = require('path');

const source = path.join(__dirname, '..', '..', 'shared', 'permissions.ts');
const destDir = path.join(__dirname, '..', 'src', '_shared');
const dest = path.join(destDir, 'permissions.ts');

if (!fs.existsSync(source)) {
  console.error(`copy-shared-permissions: expected to find ${source} but it doesn't exist.`);
  process.exit(1);
}

fs.mkdirSync(destDir, { recursive: true });
fs.copyFileSync(source, dest);
console.log('copy-shared-permissions: synced shared/permissions.ts -> backend/src/_shared/permissions.ts');